class AdversarialTrainer:
    """Curriculum-Attack TRADES with confidence-weighted KL and AWP."""
    def __init__(self, model, eps, alpha, attack_steps, num_classes, **kwargs):
        self.model = model; self.eps = eps; self.alpha = alpha
        self.attack_steps = attack_steps; self.num_classes = num_classes
        self.beta = 6.0; self.awp_gamma = 0.005
    def _loss(self, imgs, adv, labels):
        lc = self.model(imgs); la = self.model(adv)
        pc = F.softmax(lc, dim=1).detach()
        py = pc.gather(1, labels.unsqueeze(1)).squeeze(1)
        kl = F.kl_div(F.log_softmax(la, dim=1), pc, reduction='none').sum(1)
        return F.cross_entropy(lc, labels) + self.beta * ((1.0 + 0.5 * (1.0 - py)) * kl).mean()
    def train_step(self, images, labels, optimizer):
        self.model.train(); lc = self.model(images); pc = F.softmax(lc, dim=1)
        self.model.eval()
        adv = images.detach() + torch.empty_like(images).uniform_(-self.eps, self.eps)
        adv = torch.clamp(adv, 0.0, 1.0); mid = self.attack_steps // 2
        for step in range(self.attack_steps):
            adv.requires_grad_(True); la = self.model(adv)
            if step < mid:
                loss_a = F.kl_div(F.log_softmax(la, dim=1), pc.detach(), reduction='batchmean')
            else:
                loss_a = F.cross_entropy(la, labels)
            g = torch.autograd.grad(loss_a, adv)[0]; adv = adv.detach() + self.alpha * g.sign()
            adv = torch.clamp(images + torch.clamp(adv - images, -self.eps, self.eps), 0.0, 1.0).detach()
        self.model.train()
        loss1 = self._loss(images, adv, labels)
        params = [p for p in self.model.parameters() if p.requires_grad]
        grads = torch.autograd.grad(loss1, params); vs = []
        for p, g in zip(params, grads):
            v = self.awp_gamma * g if len(p.shape) > 1 else torch.zeros_like(p)
            p.data.add_(v); vs.append(v)
        optimizer.zero_grad(); loss2 = self._loss(images, adv, labels); loss2.backward()
        for p, v in zip(params, vs): p.data.sub_(v)
        optimizer.step()
        return {'loss': loss2.item()}
